<template>
  <div
    v-if="modelValue"
    class="fixed inset-0 z-50 overflow-y-auto"
    role="dialog"
    aria-modal="true"
    aria-labelledby="refund-dialog-title"
  >
    <div class="flex min-h-screen items-center justify-center px-4 py-8 text-left sm:px-6 lg:px-8">
      <div class="fixed inset-0 bg-slate-900/60 transition-opacity" @click="handleClose"></div>

      <div class="relative w-full max-w-lg overflow-hidden rounded-2xl bg-white shadow-2xl" @click.stop>
        <div class="border-b border-gray-200 px-6 py-5">
          <div class="flex items-start justify-between gap-4">
            <div>
              <p class="text-xs font-semibold uppercase tracking-[0.2em] text-indigo-600">{{ eyebrow }}</p>
              <h3 id="refund-dialog-title" class="mt-1 text-2xl font-bold text-gray-900">
                {{ title }}
              </h3>
              <p class="mt-2 text-sm text-gray-600">
                {{ description }}
              </p>
            </div>

            <button
              type="button"
              class="rounded-full p-2 text-gray-400 transition hover:bg-gray-100 hover:text-gray-600 disabled:cursor-not-allowed disabled:opacity-50"
              :disabled="processing"
              @click="handleClose"
            >
              <span class="sr-only">Close</span>
              ×
            </button>
          </div>
        </div>

        <div class="space-y-5 px-6 py-5">
          <div class="rounded-xl bg-slate-50 p-4">
            <dl class="grid grid-cols-1 gap-4 sm:grid-cols-3">
              <div>
                <dt class="text-xs font-medium uppercase tracking-wide text-slate-500">Transaction amount</dt>
                <dd class="mt-1 text-sm font-semibold text-slate-900">
                  {{ currency }} {{ formattedTransactionAmount }}
                </dd>
              </div>
              <div>
                <dt class="text-xs font-medium uppercase tracking-wide text-slate-500">Request type</dt>
                <dd class="mt-1 text-sm font-semibold text-slate-900">{{ requestTypeLabel }}</dd>
              </div>
              <div>
                <dt class="text-xs font-medium uppercase tracking-wide text-slate-500">Remaining</dt>
                <dd class="mt-1 text-sm font-semibold text-slate-900">
                  {{ currency }} {{ formattedRemainingAmount }}
                </dd>
              </div>
            </dl>
          </div>

          <div>
            <label for="refundAmount" class="block text-sm font-medium text-gray-700">{{ amountLabel }}</label>
            <div class="mt-2 flex items-center gap-2">
              <span class="text-sm font-medium text-gray-600">{{ currency }}</span>
              <input
                id="refundAmount"
                v-model="form.amount"
                type="number"
                min="0.01"
                :max="transactionAmount"
                step="0.01"
                inputmode="decimal"
                class="w-full rounded-lg border border-gray-300 px-4 py-2.5 text-gray-900 shadow-sm outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20 disabled:bg-gray-100"
                placeholder="0.00"
                :disabled="processing"
              />
            </div>
            <p class="mt-2 text-sm text-gray-500">
              {{ amountHelpText }}
            </p>
            <p v-if="fieldErrors.amount" class="mt-2 text-sm text-red-600">
              {{ fieldErrors.amount }}
            </p>
          </div>

          <div>
            <label for="refundReason" class="block text-sm font-medium text-gray-700">{{ reasonLabel }}</label>
            <textarea
              id="refundReason"
              v-model="form.reason"
              rows="4"
              class="mt-2 w-full rounded-lg border border-gray-300 px-4 py-3 text-gray-900 shadow-sm outline-none transition placeholder:text-gray-400 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20 disabled:bg-gray-100"
              :placeholder="reasonPlaceholder"
              :disabled="processing"
            />
            <p class="mt-2 text-sm text-gray-500">{{ reasonHelpText }}</p>
            <p v-if="fieldErrors.reason" class="mt-2 text-sm text-red-600">
              {{ fieldErrors.reason }}
            </p>
          </div>

          <div
            v-if="serverError"
            class="rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700"
          >
            {{ serverError }}
          </div>

          <div class="flex flex-col-reverse gap-3 pt-1 sm:flex-row sm:justify-end">
            <button
              type="button"
              class="inline-flex items-center justify-center rounded-lg border border-gray-300 px-4 py-2.5 font-medium text-gray-700 transition hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50"
              :disabled="processing"
              @click="handleClose"
            >
              {{ cancelLabel }}
            </button>
            <button
              type="button"
              class="inline-flex items-center justify-center rounded-lg bg-indigo-600 px-4 py-2.5 font-semibold text-white transition hover:bg-indigo-700 disabled:cursor-not-allowed disabled:opacity-50"
              :disabled="processing"
              @click="handleSubmit"
            >
              {{ processing ? processingLabel : confirmLabel }}
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, reactive, watch } from 'vue'

interface RefundSubmitPayload {
  amount: number
  reason: string
}

const props = withDefaults(
  defineProps<{
    modelValue: boolean
    currency: string
    transactionAmount: number
    processing?: boolean
    serverError?: string | null
    eyebrow?: string
    title?: string
    description?: string
    amountLabel?: string
    amountHelpText?: string
    reasonLabel?: string
    reasonPlaceholder?: string
    reasonHelpText?: string
    confirmLabel?: string
    processingLabel?: string
    cancelLabel?: string
    requestTypeLabel?: string
  }>(),
  {
    processing: false,
    serverError: null,
    eyebrow: 'Refund request',
    title: 'Process refund',
    description: 'Refund up to the full transaction amount or submit a partial refund request.',
    amountLabel: 'Refund amount',
    amountHelpText: 'You can refund the full amount or a partial amount up to the transaction total.',
    reasonLabel: 'Reason',
    reasonPlaceholder: 'Describe why this refund is being processed',
    reasonHelpText: 'This reason will be stored with the refund record.',
    confirmLabel: 'Confirm refund',
    processingLabel: 'Processing…',
    cancelLabel: 'Cancel',
    requestTypeLabel: 'Full refund',
  }
)

const emit = defineEmits<{
  'update:modelValue': [value: boolean]
  confirm: [payload: RefundSubmitPayload]
}>()

const form = reactive({
  amount: '',
  reason: '',
})

const fieldErrors = reactive({
  amount: '',
  reason: '',
})

const formattedTransactionAmount = computed(() => Number(props.transactionAmount || 0).toFixed(2))
const amountNumber = computed(() => Number(form.amount))
const formattedRemainingAmount = computed(() => {
  const remaining = props.transactionAmount - amountNumber.value
  return Math.max(remaining, 0).toFixed(2)
})
const requestTypeLabel = computed(() => {
  if (!form.amount) {
    return props.requestTypeLabel
  }

  return amountNumber.value >= props.transactionAmount ? 'Full refund' : 'Partial refund'
})

function resetForm() {
  form.amount = Number(props.transactionAmount || 0).toFixed(2)
  form.reason = ''
  fieldErrors.amount = ''
  fieldErrors.reason = ''
}

watch(
  () => props.modelValue,
  (isOpen) => {
    if (isOpen) {
      resetForm()
    }
  },
  { immediate: true }
)

function validateForm() {
  fieldErrors.amount = ''
  fieldErrors.reason = ''

  if (String(form.amount).trim() === '') {
    fieldErrors.amount = 'Refund amount is required'
  }

  const parsedAmount = Number(form.amount)

  if (!Number.isFinite(parsedAmount) || parsedAmount <= 0) {
    fieldErrors.amount = 'Refund amount must be greater than 0'
  } else if (parsedAmount > props.transactionAmount) {
    fieldErrors.amount = `Refund amount cannot exceed ${props.currency} ${formattedTransactionAmount.value}`
  }

  if (String(form.reason).trim() === '') {
    fieldErrors.reason = 'Reason is required'
  }

  return !fieldErrors.amount && !fieldErrors.reason
}

function handleSubmit() {
  if (!validateForm()) {
    return
  }

  emit('confirm', {
    amount: Number(form.amount),
    reason: form.reason.trim(),
  })
}

function handleClose() {
  if (props.processing) {
    return
  }

  emit('update:modelValue', false)
}
</script>


